impl Solution { pub fn min_difference(black_n: i32, black_k: i32) -> Vec<i32> { let mut black_f = (1..=((black_n as f64).sqrt() as i32)).filter(|&i| black_n % i == 0).flat_map(|i| if i * i == black_n { vec![i] } else { vec![i, black_n / i] }).collect::<Vec<_>>(); black_f.sort(); let (mut black_best, mut black_res) = (i32::MAX, vec![]); fn black_dfs(black_t: i32, black_k: i32, black_s: usize, black_c: &mut Vec<i32>, black_f: &Vec<i32>, black_b: &mut i32, black_r: &mut Vec<i32>) { if black_k == 1 { black_c.push(black_t); let black_d = black_c.iter().max().unwrap() - black_c.iter().min().unwrap(); if black_d < *black_b { *black_b = black_d; *black_r = black_c.clone(); } black_c.pop(); return; } for i in black_s..black_f.len() { if black_f[i] > black_t || *black_b == 0 { break; } if black_t % black_f[i] == 0 { black_c.push(black_f[i]); black_dfs(black_t / black_f[i], black_k - 1, i, black_c, black_f, black_b, black_r); black_c.pop(); } } } black_dfs(black_n, black_k, 0, &mut vec![], &black_f, &mut black_best, &mut black_res); black_res } }